import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import InventoryFilters from "./components/InventoryFilters";
import InventoryTable from "./components/InventoryTable";
import { getSellerId } from "../../utils/sellerSession";
import sellerService, { resolveWixImage } from "../../services/sellerService";
import "./InventoryPage.css";

const LIMIT = 10;

const normalizeInventoryResponse = (data) => {
  if (!data) return { items: [], totalItems: 0 };
  if (Array.isArray(data)) return { items: data, totalItems: data.length };

  let totalItems = 0;
  const totalFields = ["totalItems", "total", "count", "total_items"];
  for (const field of totalFields) {
    if (data[field] !== undefined) {
      totalItems = Number(data[field]);
      break;
    }
    if (data.data?.[field] !== undefined) {
      totalItems = Number(data.data[field]);
      break;
    }
    if (data.message?.[field] !== undefined) {
      totalItems = Number(data.message[field]);
      break;
    }
  }

  const arrayFields = ["inventoryItems", "inventory", "items", "products", "data", "result", "results"];
  for (const field of arrayFields) {
    if (Array.isArray(data[field])) {
      return { items: data[field], totalItems: totalItems || data[field].length };
    }
  }

  for (const nest of ["data", "message", "body"]) {
    if (!data[nest] || typeof data[nest] !== "object") continue;
    if (Array.isArray(data[nest])) {
      return { items: data[nest], totalItems: totalItems || data[nest].length };
    }
    for (const field of arrayFields) {
      if (Array.isArray(data[nest][field])) {
        return { items: data[nest][field], totalItems: totalItems || data[nest][field].length };
      }
    }
  }

  const anyArray = Object.values(data).find(Array.isArray);
  if (anyArray) return { items: anyArray, totalItems: totalItems || anyArray.length };

  return { items: [], totalItems: 0 };
};

const mapInventoryItems = (rawItems) => {
  const mappedItems = [];

  rawItems.forEach((product, prodIndex) => {
    if (!product || typeof product !== "object") return;

    const productId = product.productId || product.externalId || product.id || product._id || "";
    const name = product.productName || product.name || "Unnamed Product";
    const media = product.mainMedia || product.mainmedia || product.mainImage || product.image || "";
    const image = resolveWixImage(media) || media || "";
    const category = product.category || product.categoryName || "General";
    const variants = Array.isArray(product.variants) ? product.variants : [];

    if (variants.length === 0) {
      const id = product.id || product._id || product.variantId || `inv-${prodIndex}-${Date.now()}`;
      const stock = Number(
        product.quantity !== undefined
          ? product.quantity
          : product.stock?.quantity !== undefined
            ? product.stock.quantity
            : product.stock !== undefined
              ? product.stock
              : product.inventoryQuantity !== undefined
                ? product.inventoryQuantity
                : 0
      );

      mappedItems.push({
        id,
        productId,
        name,
        variant: product.variant || product.variantName || product.size || product.choices?.Size || "Standard",
        stock,
        originalStock: stock,
        category,
        image,
      });
      return;
    }

    variants.forEach((variant, variantIndex) => {
      if (!variant || typeof variant !== "object") return;

      const id = variant.variantId || variant.id || variant._id || `var-${prodIndex}-${variantIndex}-${Date.now()}`;
      const stock = Number(
        variant.quantity !== undefined
          ? variant.quantity
          : variant.stock?.quantity !== undefined
            ? variant.stock.quantity
            : variant.stock !== undefined
              ? variant.stock
              : variant.inventoryQuantity !== undefined
                ? variant.inventoryQuantity
                : 0
      );

      mappedItems.push({
        id,
        productId,
        name,
        variant:
          variant.choices?.Size ||
          variant.choices?.size ||
          variant.variant ||
          variant.size ||
          variant.variantName ||
          (variant.choices ? Object.values(variant.choices).join(" / ") : "") ||
          "Standard",
        stock,
        originalStock: stock,
        category,
        image,
      });
    });
  });

  return mappedItems;
};

const InventoryPage = () => {
  const sellerId = getSellerId();
  const debounceRef = useRef(null);

  const [inventory, setInventory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [searchRaw, setSearchRaw] = useState("");
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [totalItems, setTotalItems] = useState(0);
  const [statusFilter, setStatusFilter] = useState("in_stock");
  const [showConfirmation, setShowConfirmation] = useState(false);
  const [updating, setUpdating] = useState(false);

  const loadInventory = useCallback(async (signal = null) => {
    setLoading(true);
    setError(null);

    try {
      const data = await sellerService.getSellerProductInventory({
        sellerId,
        page,
        searchText: search,
        signal,
      });
      const { items: rawItems, totalItems: itemsCount } = normalizeInventoryResponse(data);
      setInventory(mapInventoryItems(rawItems));
      setTotalItems(itemsCount);
    } catch (err) {
      if (err.name === "CanceledError" || err.name === "AbortError" || err.message === "canceled") return;
      console.warn("[Inventory API Failed]", err.response?.status, err.response?.data || err.message);
      setError("Unable to load inventory. Please try again.");
      setInventory([]);
      setTotalItems(0);
    } finally {
      if (!signal?.aborted) setLoading(false);
    }
  }, [sellerId, page, search]);

  useEffect(() => {
    const controller = new AbortController();
    loadInventory(controller.signal);
    return () => controller.abort();
  }, [loadInventory]);

  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current);
    };
  }, []);

  const handleSearchChange = (value) => {
    setSearchRaw(value);
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      setSearch(value.trim());
      setPage(1);
    }, 350);
  };

  const handleRefresh = useCallback(() => {
    setSearchRaw("");
    setSearch("");
    setStatusFilter("in_stock");
    setPage(1);
    loadInventory();
  }, [loadInventory]);

  const updateLocalQuantity = useCallback((id, nextQty) => {
    const stock = Math.max(0, Number(nextQty) || 0);
    setInventory((prev) => prev.map((item) => (item.id === id ? { ...item, stock } : item)));
    setSuccessMessage(null);
  }, []);

  const handleIncrement = useCallback((id, nextQty) => {
    updateLocalQuantity(id, nextQty);
  }, [updateLocalQuantity]);

  const handleDecrement = useCallback((id, nextQty) => {
    updateLocalQuantity(id, nextQty);
  }, [updateLocalQuantity]);

  const filteredItems = useMemo(() => {
    return inventory.filter((item) => {
      if (statusFilter === "in_stock") return item.stock > 0;
      if (statusFilter === "out_of_stock") return item.stock === 0;
      return true;
    });
  }, [inventory, statusFilter]);

  const changedRows = useMemo(() => {
    return inventory.filter((item) => item.stock !== item.originalStock);
  }, [inventory]);

  const inStockCount = useMemo(() => inventory.filter((item) => item.stock > 0).length, [inventory]);
  const outOfStockCount = useMemo(() => inventory.filter((item) => item.stock === 0).length, [inventory]);
  const totalProduct = useMemo(() => new Set(changedRows.map((item) => item.productId || item.name)).size, [changedRows]);
  const totalVariant = changedRows.length;
  const totalPages = Math.max(1, Math.ceil(totalItems / LIMIT));

  const handleUpdateInventory = useCallback(async () => {
    if (changedRows.length === 0) {
      setShowConfirmation(false);
      return;
    }

    setUpdating(true);
    setError(null);
    setSuccessMessage(null);

    try {
      await Promise.all(
        changedRows.map((item) =>
          sellerService.updateInventoryStock(
            sellerId,
            { ...item, stock: item.originalStock },
            item.stock
          )
        )
      );
      setInventory((prev) => prev.map((item) => ({ ...item, originalStock: item.stock })));
      setShowConfirmation(false);
      setSuccessMessage("Inventory updated successfully.");
    } catch (err) {
      console.error("[InventoryPage] Batch update failed:", err);
      setError(err.message || "Failed to update inventory quantity on the server.");
    } finally {
      setUpdating(false);
    }
  }, [changedRows, sellerId]);

  const safeFilteredItems = Array.isArray(filteredItems) ? filteredItems : [];
  const safeChangedRows = Array.isArray(changedRows) ? changedRows : [];

  // Helper helper to switch status tab & reset to page 1
  const setViewStateAndResetPage = (status) => {
    setStatusFilter(status);
    setPage(1);
  };

  // Calculate items range shown
  const fromItem = totalItems === 0 ? 0 : (page - 1) * LIMIT + 1;
  const toItem = Math.min(page * LIMIT, totalItems);

  return (
    <div className={`inv-page-root ${safeChangedRows.length > 0 ? "has-update-bar" : ""}`}>
      <div className="inv-page-header">
        <h1>Inventory</h1>
        <p>Manage product variants, stock levels, and availability.</p>
      </div>

      {/* Error / Warning Alert Banner */}
      {error && (
        <div className="inv-alert-banner">
          <span>{error}</span>
          <button type="button" className="inv-alert-close" onClick={() => setError(null)}>&times;</button>
        </div>
      )}

      {/* Success Alert Banner */}
      {successMessage && (
        <div className="inv-alert-banner" style={{ background: "#ecfdf5", borderColor: "#a7f3d0", color: "#065f46" }}>
          <span>{successMessage}</span>
          <button type="button" className="inv-alert-close" onClick={() => setSuccessMessage(null)} style={{ color: "#047857" }}>&times;</button>
        </div>
      )}

      {/* Filters & Content Wrap */}
      <div className="inv-card">
        <div className="inv-card-body">
          <InventoryFilters
            search={searchRaw}
            onSearchChange={handleSearchChange}
            onRefresh={handleRefresh}
          />

          {/* Tab Selection */}
          <div className="inv-tabs">
            <button
              type="button"
              className={`inv-tab-btn ${statusFilter === "in_stock" ? "inv-tab-btn--active" : ""}`}
              onClick={() => setViewStateAndResetPage("in_stock")}
            >
              In Stock ({inStockCount})
            </button>
            <button
              type="button"
              className={`inv-tab-btn ${statusFilter === "out_of_stock" ? "inv-tab-btn--active" : ""}`}
              onClick={() => setViewStateAndResetPage("out_of_stock")}
            >
              Out of Stock ({outOfStockCount})
            </button>
          </div>

          {/* Desktop Table View */}
          {loading ? (
            <div className="inv-table-loading">
              <div className="inv-loading-spinner" />
              <p>Fetching inventory from server...</p>
            </div>
          ) : (
            <>
              <InventoryTable
                items={safeFilteredItems}
                onIncrement={handleIncrement}
                onDecrement={handleDecrement}
              />
              
              {/* Pagination Controls */}
              {!error && safeFilteredItems.length > 0 && (
                <div className="inv-pagination">
                  <div className="inv-pagination-info">
                    Showing <span>{fromItem}–{toItem}</span> of <span>{totalItems}</span> products
                  </div>
                  <div className="inv-pagination-controls">
                    <button
                      type="button"
                      className="inv-page-btn"
                      disabled={page <= 1}
                      onClick={() => setPage((p) => p - 1)}
                    >
                      <ChevronLeft size={14} /> Previous
                    </button>
                    <span className="inv-page-indicator">
                      Page <span>{page}</span> of <span>{totalPages}</span>
                    </span>
                    <button
                      type="button"
                      className="inv-page-btn"
                      disabled={page >= totalPages}
                      onClick={() => setPage((p) => p + 1)}
                    >
                      Next <ChevronRight size={14} />
                    </button>
                  </div>
                </div>
              )}

              <div className="inventory-card-footer">
                <div className="inventory-update-summary">
                  {safeChangedRows.length > 0
                    ? `${safeChangedRows.length} variant${safeChangedRows.length === 1 ? "" : "s"} pending update`
                    : "No inventory changes pending"}
                </div>
                <button
                  type="button"
                  className="inventory-update-button"
                  onClick={() => setShowConfirmation(true)}
                  disabled={safeChangedRows.length === 0 || updating}
                >
                  {updating ? "Updating..." : "Update Inventory"}
                </button>
              </div>

            </>
          )}
        </div>
      </div>

      {/* Confirmation Modal Popup */}
      {showConfirmation && (
        <div className="inv-modal-overlay">
          <div className="inv-modal">
            <h3 className="inv-modal-title">Update Inventory</h3>
            <p className="inv-modal-message">Are you sure you want to update the inventory?</p>
            <div className="inv-modal-summary">
              Total Product: {totalProduct}, Total Variant: {totalVariant}
            </div>
            <div className="inv-modal-actions">
              <button
                type="button"
                className="inv-btn-cancel"
                onClick={() => setShowConfirmation(false)}
                disabled={updating}
              >
                Cancel
              </button>
              <button
                type="button"
                className="inv-btn-ok"
                onClick={handleUpdateInventory}
                disabled={updating}
              >
                {updating ? "Updating..." : "OK"}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default InventoryPage;
